package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_defaultFalse() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class,
                String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_trueWhenSetWithIgnoreHeaderCaseTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_falseWhenSetWithIgnoreHeaderCaseFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_onPredefinedFormats() {
        assertFalse(CSVFormat.DEFAULT.getIgnoreHeaderCase());
        assertFalse(CSVFormat.EXCEL.getIgnoreHeaderCase());
        assertFalse(CSVFormat.INFORMIX_UNLOAD.getIgnoreHeaderCase());
        assertFalse(CSVFormat.INFORMIX_UNLOAD_CSV.getIgnoreHeaderCase());
        assertFalse(CSVFormat.MYSQL.getIgnoreHeaderCase());
        assertFalse(CSVFormat.POSTGRESQL_CSV.getIgnoreHeaderCase());
        assertFalse(CSVFormat.POSTGRESQL_TEXT.getIgnoreHeaderCase());
        assertFalse(CSVFormat.RFC4180.getIgnoreHeaderCase());
        assertFalse(CSVFormat.TDF.getIgnoreHeaderCase());
    }
}
